// filterRowAlpine builds the x-data="filterRow([...])" snippet with the
// initial active list pre-populated from inputs that already have a
// value (the fields that came in via the URL).
func filterRowAlpine(inputs []props.FilterInput) string {
	var active []string
	for _, in := range inputs {
		if len(in.Values) > 0 {
			active = append(active, "'"+in.Name+"'")
		}
	}
	return "filterRow([" + strings.Join(active, ",") + "])"
}

// filterFirstValue returns the first element of a string slice or empty.
// Used by single-value editor branches (text input, plain <select>) to
// pull a representative value from the multi-capable Values field.
func filterFirstValue(vs []string) string {
	if len(vs) == 0 {
		return ""
	}
	return vs[0]
}

// filterHasColours reports whether any option carries a TagStatus colour —
// the signal to render the chip with popui.DropdownSelect instead of a
// plain <select>.
func filterHasColours(opts []props.FilterOption) bool {
	for _, o := range opts {
		if o.Color != "" {
			return true
		}
	}
	return false
}

// filterDropdownOptions translates FilterOption into props.DropdownSelectOption
// — same Color vocabulary, just a different struct.
func filterDropdownOptions(opts []props.FilterOption) []props.DropdownSelectOption {
	out := make([]props.DropdownSelectOption, len(opts))
	for i, o := range opts {
		out[i] = props.DropdownSelectOption{Value: o.Value, Label: o.Label, Color: o.Color}
	}
	return out
}

